// Rates/converter/analytics/chart are no longer toggleable widgets here —
// they moved into #tools-modal (see openToolsManager above) and are always
// reachable from there, so only the one section still living inline in
// the Finance tab's scroll (goals) needs a show/hide+reorder toggle.
const WIDGET_DEFS=[
  {key:'goals', icon:'flag', color:'#10b981', titleKey:'widgets_item_goals', subKey:'widgets_item_goals_sub'},
];

function renderWidgetsList(){
  const box=document.getElementById('widgets-list'); if(!box) return;
  const defByKey=Object.fromEntries(WIDGET_DEFS.map(w=>[w.key,w]));
  box.innerHTML=AppState.widgetOrder.map((key,i)=>{
    const w=defByKey[key]; if(!w) return '';
    return `
    <div class="settings-row" style="cursor:default">
      <span class="icon-badge" style="background:${w.color}">${window.Icon(w.icon)}</span>
      <div class="settings-row-text">
        <div class="settings-row-title">${tr(w.titleKey)}</div>
        <div class="settings-row-sub">${tr(w.subKey)}</div>
      </div>
      <div class="widget-reorder-col">
        <button type="button" class="widget-reorder-btn" ${i===0?'disabled':''} data-action="move-widget" data-key="${key}" data-dir="-1" aria-label="${tr('widgets_move_up')}">${window.Icon('chevron')}</button>
        <button type="button" class="widget-reorder-btn widget-reorder-down" ${i===AppState.widgetOrder.length-1?'disabled':''} data-action="move-widget" data-key="${key}" data-dir="1" aria-label="${tr('widgets_move_down')}">${window.Icon('chevron')}</button>
      </div>
      <label class="toggle">
        <input type="checkbox" ${AppState.widgets[key]!==false?'checked':''} data-action="toggle-widget" data-key="${key}">
        <span class="toggle-track"></span>
      </label>
    </div>`;
  }).join('');
}

const toggleWidget = function(key, on){
  AppState.widgets[key]=!!on;
  saveConfigLocal(); scheduleSave();
  applyWidgetVisibility();
};

const moveWidget = function(key, dir){
  const i=AppState.widgetOrder.indexOf(key);
  const j=i+dir;
  if(i<0||j<0||j>=AppState.widgetOrder.length) return;
  [AppState.widgetOrder[i],AppState.widgetOrder[j]]=[AppState.widgetOrder[j],AppState.widgetOrder[i]];
  saveConfigLocal(); scheduleSave();
  renderWidgetsList();
  applyWidgetOrder();
};

export function syncHideAmountsButton(on=document.body.classList.contains('amounts-hidden')){
  const btn=document.getElementById('btn-hide-amounts');
  if(btn){
    btn.innerHTML=window.Icon(on?'eyeOff':'eye');
    btn.classList.toggle('is-active', on);
    btn.setAttribute('aria-pressed', on?'true':'false');
    btn.setAttribute('aria-label', on?'Показати суми':'Сховати суми');
  }
}

export const toggleHideAmounts = function(){
  const on=!document.body.classList.contains('amounts-hidden');
  document.body.classList.toggle('amounts-hidden', on);
  try{ localStorage.setItem('mxHideAmounts', on?'1':'0'); }catch(e){}
  syncHideAmountsButton(on);
};

